import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Limit user input to a maximum of 10 characters
        String safeInput = userInput.substring(0, Math.min(userInput.length(), 10));

        // Print the sanitized input
        System.out.println("Sanitized input: " + safeInput);

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
